#include <iostream>
#include <string>
using namespace std;

int main()
{
    // for dongusu
    cout << "1'den 5'e kadar:" << endl;
    for (int i = 1; i <= 5; i++)
    {
        cout << "Sayi: " << i << endl;
    }

    // while dongusu
    cout << "\nGeri sayim:" << endl;
    int counter = 5;
    while (counter > 0)
    {
        cout << counter << endl;
        counter--;
    }

    // for-each (range-based for) dongusu
    cout << "\nMeyveler:" << endl;
    string fruits[] = {"Elma", "Armut", "Muz", "Karpuz"};
    for (const string& fruit : fruits)
    {
        cout << "- " << fruit << endl;
    }

    // do-while dongusu
    cout << "\nDo-while ornegi:" << endl;
    int n = 0;
    do
    {
        cout << "n = " << n << endl;
        n++;
    } while (n < 3);

    return 0;
}
